"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([[748],{4169:e=>{e.exports=JSON.parse('{"label":"shellcode","permalink":"/docs/tags/shellcode","allTagsPath":"/docs/tags","count":1,"items":[{"id":"ctf-writeups/2023/hackasat-qualifier/riscv-smash-baby","title":"RISC-V Smash Baby - Hack-A-Sat Qualifier 2023","description":"Hello fellow hackers! Today we\'re attempting to solve the RISC-V Smash Baby challenge from the Pure Pwnage category of Hack-A-Sat Qualifier 2023 CTF. The program first leaks the memory address where the flag is stored on the main function stack and stores the flag to disk. A function vulnerable to buffer overflow can be reached by satisfying some value checks. Hence, the flag can be obtained by uploading shellcode that will print the string located at the leaked memory address, or by spawning a shell and printing the flag.","permalink":"/docs/ctf-writeups/2023/hackasat-qualifier/riscv-smash-baby"}],"unlisted":false}')}}]);